let lrgrep_execute_error_messages keywords
  (__clause, (__registers : Parser_raw.MenhirInterpreter.element Lrgrep_runtime.register_values))
  ((token : Parser_raw.MenhirInterpreter.token), _startloc_token_, _endloc_token_)
  : _ option = match __clause, token with
  | 0, (ELSE) ->
    let e, _startpos_e_, _endpos_e_, _positions_e_ = match __registers.(0) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (st, x, startp, endp)) ->
        let x = match Parser_raw.MenhirInterpreter.incoming_symbol st with
          | N N_fun_expr -> (x : Parsetree.expression)
          | _ -> assert false
        in
        (x, startp, endp, (startp, endp))
    in
    let _ = e in
    (
# 35 "parse_errors.lrgrep"
            
    match e with
    | {pexp_desc = Pexp_ifthenelse(_, _, None); _} -> (
      Some ("The semicolon " ^ line_and_char _startpos_e_
            ^ " terminates the `if ... then ...` expression. \
            Remove it to add an else branch.")
      )
    | _ -> None
  
# 63 "parse_errors.ml"
    )
  | (0), _ -> None
  | 1, _ ->
    let typs, _startpos_typs_, _endpos_typs_, _positions_typs_ = match __registers.(0) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (st, x, startp, endp)) ->
        let x = match Parser_raw.MenhirInterpreter.incoming_symbol st with
          | N N_reversed_separated_nontrivial_llist_COMMA_core_type_ -> (x : Parsetree.core_type list)
          | _ -> assert false
        in
        (x, startp, endp, (startp, endp))
    in
    let _ = typs in
    let rp, _startpos_rp_, _endpos_rp_, _positions_rp_ = match __registers.(1) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (st, x, startp, endp)) ->
        let x = match Parser_raw.MenhirInterpreter.incoming_symbol st with
          | T T_RPAREN -> (x : unit)
          | _ -> assert false
        in
        (x, startp, endp, (startp, endp))
    in
    let _ = rp in
    (
# 48 "parse_errors.lrgrep"
            
    match List.rev typs with
    | [] | [_] -> None
    | typs -> Some Ast_helper.(
      Printf.sprintf
        "The preceding type ending %s is incomplete.\n\
         It's missing a type constructor after the parameters, for instance: %s.\n\
         If you meant to write a tuple, use '*': %s."
        (line_and_char _endpos_rp_)
        (Format.asprintf "%a" Pprintast.core_type
          (Typ.constr (Location.mknoloc (Longident.Lident "t")) typs))
        (Format.asprintf "%a" Pprintast.core_type
          (Typ.tuple (List.map (fun t -> (None,t)) typs)))
    )
  
# 106 "parse_errors.ml"
    )
  | 2, (EQUAL) ->
    Some (
# 65 "parse_errors.lrgrep"
    "Expecting ':' to declare the type of a record field, not '='" 
# 112 "parse_errors.ml"
    )
  | (2), _ -> None
  | 3, _ ->
    let semi, _startpos_semi_, _endpos_semi_, _positions_semi_ = match __registers.(0) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (st, x, startp, endp)) ->
        let x = match Parser_raw.MenhirInterpreter.incoming_symbol st with
          | T T_SEMI -> (x : unit)
          | _ -> assert false
        in
        (x, startp, endp, (startp, endp))
    in
    let _ = semi in
    Some (
# 70 "parse_errors.lrgrep"
    "Expecting 'in' to complete local-let binding. Hint: this might be due to the semicolon " ^ line_and_char _startpos_semi_ 
# 130 "parse_errors.ml"
    )
  | 4, _ ->
    let loc, _startpos_loc_, _endpos_loc_, _positions_loc_ = match __registers.(0) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (_, _, startp, endp)as x) ->
        (x, startp, endp, (startp, endp))
    in
    let _ = loc in
    Some (
# 73 "parse_errors.lrgrep"
    "Expecting 'in' after let binding(s) in an expression. \n\
     This might be due to the unterminated expression at " ^
     line_and_char _endpos_loc_ 
# 145 "parse_errors.ml"
    )
  | 5, (IN) ->
    let item, _startpos_item_, _endpos_item_, _positions_item_ = match __registers.(0) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (st, x, startp, endp)) ->
        let x = match Parser_raw.MenhirInterpreter.incoming_symbol st with
          | N N_structure_item -> (x : Parsetree.structure_item)
