# 163 "parse_errors.ml"
    )
  | (5), _ -> None
  | 6, _ ->
    let lp, _startpos_lp_, _endpos_lp_, _positions_lp_ = match __registers.(0) with 
      | Empty -> assert false
      | Location _ -> assert false
      | Value (Parser_raw.MenhirInterpreter.Element (st, x, startp, endp)) ->
        let x = match Parser_raw.MenhirInterpreter.incoming_symbol st with
          | T T_LPAREN -> (x : unit)
          | _ -> assert false
        in
        (x, startp, endp, (startp, endp))
    in
    let _ = lp in
    Some (
# 83 "parse_errors.lrgrep"
    "Unclosed parenthesis at " ^ line_and_char _startpos_lp_ 
# 181 "parse_errors.ml"
    )
  | 7, _ ->
    let _startpos_pos_ = match __registers.(0) with
      | Empty -> assert false
      | Location (p, _) | Value (Parser_raw.MenhirInterpreter.Element (_, _, p, _)) -> p
    in
    let _endpos_pos_ = match __registers.(1) with
      | Empty -> assert false
      | Location (_, p) | Value (Parser_raw.MenhirInterpreter.Element (_, _, _, p)) -> p
    in
    Some (
# 88 "parse_errors.lrgrep"
    "Expecting `in' to continue let-binding at " ^ line_and_char _startpos_pos_ 
# 195 "parse_errors.ml"
    )
  | 8, _ ->
    (
# 94 "parse_errors.lrgrep"
             match Lexer_raw.as_keyword keywords token with
    | None -> None
    | Some kw ->
      Some ("`" ^ kw ^ "' is a keyword and cannot appear in this context (try " ^ kw ^ "_)")
  
# 205 "parse_errors.ml"
    )
  | 9, (MODULE) ->
    Some (
# 106 "parse_errors.lrgrep"
     "`module' keyword cannot appear in an expression, \
       use `(module M)' to pack a first class-module \
       or `let module M = ... in ...' to define a local module"
  
# 214 "parse_errors.ml"
    )
  | (9), _ -> None
  | 10, (MINUSGREATER) ->
    Some (
# 114 "parse_errors.lrgrep"
    "Issue #11445: in constructor arguments, \
     arrow types should be wrapped between parentheses"
  
# 223 "parse_errors.ml"
    )
  | (10), _ -> None
